#!/usr/bin/env python3\nimport json\nfrom pathlib import Path\n\nROOT = Path(__file__).resolve().parents[1]\nARTIFACT = ROOT / "artifacts" / "gravity" / "pbh_thermal_evaporation_source_map_2026_05_22.json"\n\ndata = json.loads(ARTIFACT.read_text())\n\nassert data["id"] == "PBH_THERMAL_EVAPORATION_SOURCE_MAP_2026_05_22"\nassert data["status"] == "MODEL_SPECIFIC_PBH_THERMAL_EVAPORATION_SOURCE_ONLY_NO_GRAVITY_CLOSURE"\n\nsource = data["source"]\nassert source["title"] == "Evaporation of primordial black holes in a thermal universe: a thermofield dynamics approach"\nassert source["arxiv"] == "2512.07284"\nassert source["doi"] == "10.1007/JHEP04(2026)026"\nassert source["journal"] == "Journal of High Energy Physics"\nassert source["published"] == "2026-04-02"\nassert source["url"] == "https://link.springer.com/article/10.1007/JHEP04(2026)026"\n\nfor supplied in [\n    "MODEL_SPECIFIC_PBH_THERMAL_EVAPORATION_SOURCE",\n    "THERMOFIELD_DYNAMICS_HAWKING_SPECTRUM_SOURCE",\n    "REHEATING_BATH_EVAPORATION_RATE_SOURCE",\n    "PBH_LIFETIME_SHORTENING_SOURCE",\n]:\n    assert supplied in data["supplies"]\n\ndoes_not_supply = set(data["does_not_supply"])\nfor missing in [\n    "CHRONOS_GRAVITY_STACK_BINDING_MAP",\n    "FOUR_DIMENSIONAL_GRAVITY_CLOSURE_THEOREM",\n    "UNRESTRICTED_PBH_DARK_MATTER_VALIDATION",\n    "EMPIRICAL_PBH_ABUNDANCE_VALIDATION",\n    "SIX_FIELD_ANALYTIC_PACKAGE_HYPOTHESIS",\n]:\n    assert missing in does_not_supply\n\nassert data["weakest_sufficient_missing_lemma"] == "MODEL_SPECIFIC_PBH_THERMAL_EVAPORATION_TO_CHRONOS_GRAVITY_STACK_BINDING_MAP"\n\nsecondary = set(data["secondary_missing_lemmas"])\nfor lemma in [\n    "THERMAL_BATH_MODEL_TO_CHRONOS_ADMISSIBLE_DATA_MAP",\n    "PBH_EVAPORATION_RATE_TO_GRAVITY_STACK_OBSERVABLE_MAP",\n    "PBH_LIFETIME_CORRECTION_TO_EMPIRICAL_CONSTRAINT_MAP",\n    "THERMOFIELD_DYNAMICS_TO_BOUNDARY_COMPACTNESS_INTERFACE",\n]:\n    assert lemma in secondary\n\nboundary = "\n".join(data["boundary"])\nfor line in [\n    "Model-specific PBH thermal-evaporation source only.",\n    "No gravity closure is claimed.",\n    "No Chronos gravity stack binding map is claimed.",\n    "No unrestricted primordial black hole evaporation theorem is claimed.",\n    "No unrestricted primordial black hole formation theorem is claimed.",\n    "No dark matter detection is claimed.",\n    "No dark matter resolution is claimed.",\n    "No DFM-MKC validation is claimed.",\n    "No Lambda-CDM failure is claimed.",\n    "No cosmic censorship result is claimed.",\n    "No hoop conjecture result is claimed.",\n    "No four-dimensional non-symmetric collapse theorem is claimed.",\n    "No empirical validation is claimed.",\n    "No Clay problem is claimed.",\n]:\n    assert line in boundary\n\ndoes_not_prove = set(data["does_not_prove"])\nfor forbidden in [\n    "gravity closure",\n    "Chronos gravity stack binding map",\n    "unrestricted primordial black hole evaporation theorem",\n    "unrestricted primordial black hole formation theorem",\n    "dark matter detection",\n    "dark matter resolution",\n    "DFM-MKC validation",\n    "Lambda-CDM failure",\n    "cosmic censorship",\n    "hoop conjecture",\n    "four-dimensional non-symmetric collapse theorem",\n    "empirical validation",\n    "any Clay problem",\n]:\n    assert forbidden in does_not_prove\n\nprint("PBH thermal-evaporation source-map verification OK.")\nprint("Status: {}".format(data["status"]))\nprint("Weakest sufficient missing lemma: {}".format(data["weakest_sufficient_missing_lemma"]))\n